import { useState, useEffect, useRef, useMemo } from 'react';
import { Position } from 'reactflow';
import { DocumentTextIcon } from '@heroicons/react/24/outline';
import { BaseNode } from './BaseNode';
import { useStore } from '../store';

export const TextNode = ({ id, data }) => {
  const [currText, setCurrText] = useState(data?.text || '{{input}}');
  const [variables, setVariables] = useState([]);
  const updateNodeField = useStore(state => state.updateNodeField);
  const textareaRef = useRef(null);

  const varRegex = /\{\{\s*([a-zA-Z_$][a-zA-Z0-9_$]*)\s*\}\}/g;

  useEffect(() => {
    const matches = [...currText.matchAll(varRegex)];
    const uniqueVars = [...new Set(matches.map(m => m[1]))];
    setVariables(uniqueVars);
  }, [currText]);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
    }
  }, [currText]);

  const handleTextChange = (e) => {
    const val = e.target.value;
    setCurrText(val);
    updateNodeField(id, 'text', val);
  };

  const handles = useMemo(() => {
    const inputHandles = variables.map((v, i) => ({
      type: 'target',
      position: Position.Left,
      id: `${id}-${v}`,
      style: { top: `${(i + 1) * (100 / (variables.length + 1))}%` },
      className: '!bg-primary',
    }));

    return [
      ...inputHandles,
      { type: 'source', position: Position.Right, id: `${id}-output`, color: 'bg-primary' }
    ];
  }, [id, variables]);

  return (
    <BaseNode id={id} title="Text" icon={DocumentTextIcon} themeColor="primary" handles={handles} width={300}>
      <div className="flex flex-col gap-3">
        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Content</label>
        <textarea
          ref={textareaRef}
          value={currText}
          onChange={handleTextChange}
          placeholder="Type {{variable}} to create handles..."
          className="w-full bg-[#050505]/50 border border-slate-700/50 rounded-lg px-4 py-3 text-sm text-slate-200 focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary transition-all resize-none overflow-hidden font-mono leading-relaxed min-h-[80px]"
          rows={1}
        />
        {variables.length > 0 && (
          <div className="flex flex-wrap gap-1.5 mt-2">
            {variables.map(v => (
              <span key={v} className="bg-primary/10 text-primary text-[10px] px-2 py-0.5 rounded-full border border-primary/20 font-mono">
                {v}
              </span>
            ))}
          </div>
        )}
      </div>
    </BaseNode>
  );
};
